object Solution { def realized_pnl_by_symbol(trades: Seq[Map[String, Any]]): Map[String, Int] = { val lots = scala.collection.mutable.Map[String, scala.collection.mutable.ArrayBuffer[(Int, Int)]](); val totals = scala.collection.mutable.Map[String, Int]().withDefaultValue(0); for (trade <- trades) { val symbol = trade("symbol").toString; val queue = lots.getOrElseUpdate(symbol, scala.collection.mutable.ArrayBuffer[(Int, Int)]()); if (trade("side") == "BUY") queue += ((asInt(trade("qty")), asInt(trade("price")))) else { totals.getOrElseUpdate(symbol, 0); var remaining = asInt(trade("qty")); val price = asInt(trade("price")); while (remaining > 0 && queue.nonEmpty) { val (lotQty, lotPrice) = queue.remove(0); val matched = math.min(remaining, lotQty); totals(symbol) += (price - lotPrice) * matched; remaining -= matched; if (matched < lotQty) queue.insert(0, (lotQty - matched, lotPrice)) } } }; totals.toMap }; private def asInt(value: Any): Int = value match { case n: Int => n; case n: Long => n.toInt; case n: Double => n.toInt; case _ => 0 } }
